public static long ANDequalOR(int n, int[] arr) {
    long ans = 0;
    int pre = 0;
    long count = 0;
    for (int i = 0; i < n; i++) {
        if (arr[i] == arr[pre]) {
            count++;
        } else {
            ans += (count * (count + 1)) / 2;
            pre = i;
            count = 1;
        }
    }
    ans += (count * (count + 1)) / 2;
    return ans;
}

