def ANDequalOR( n: int, arr: List[int]) -> int:
    ans = 0
    pre = 0
    count = 0
    for i in range(n):
        if arr[i] == arr[pre]:
            count += 1
        else:
            ans += (count * (count + 1)) // 2
            pre = i
            count = 1
    ans += (count * (count + 1)) // 2
    return ans

