public static boolean AreEqual(String a, String b) {
    int n = a.length();
    boolean flag = false;
    for (int i = 0; i < n - 1; i++) {
        if (a.charAt(i) == '0' && b.charAt(i + 1) == '1') {
            if (a.charAt(i) == b.charAt(i) && a.charAt(i + 1) == b.charAt(i + 1)) {
                flag = true;
            }
        }
    }
