public static int[] matchingCnt(int n, String[] X) {
    Map<Integer, int[]> map = new HashMap<>();
    int[] ans = new int[n];
    for (int i = n - 1; i >= 0; i--) {
        String x = X[i];
        int cans = 0;
        for (int j = 0; j < x.length(); j++) {
            if (!map.containsKey(j)) {
                map.put(j, new int[26]);
            }
            cans = cans + map.get(j)[x.charAt(j) - 'a'];
            map.get(j)[x.charAt(j) - 'a']++;
        }
        ans[i] = cans;
    }
    return ans;
}

