public static int countSuperPalindrome(int l, int r) {
    int count = 0;

    int start = (int)Math.ceil(Math.sqrt(l));

    while (start * start <= r) {

        int square = start * start;
        String s = Integer.toString(square);

        if (s.equals(new StringBuilder(s).reverse().toString())) {
            count++;
        }
        start++;
    }
    return count;
}

