public static int minimizeArr(int n, int[] arr) {

    int mi = Arrays.stream(arr).min().getAsInt();
    int ct = 0;

    for (int j : arr) {
        if (j == mi) ct++;
    }

    if (ct == 1) return 1;

    for (int j : arr) {
        if (j % mi != 0) return 1;
    }

    return (int)Math.ceil((float)ct / 2);
}

