public static int minimumPushes(String word) {
    int[] cnt = new int[26];
    for (char b : word.toCharArray()) {
        cnt[b - 'a']++;
    }
    Arrays.sort(cnt);
    int ans = 0;
    for (int i = 0; i < 26; i++) {
        ans += cnt[25 - i] * (i / 8 + 1);
    }
    return ans;
}

