public static int minimumOperationsToWriteY(int[][] grid) {
    int[] cnt1 = new int[3];
    int[] cnt2 = new int[3];
    int n = grid.length;
    int m = n / 2;
    for (int i = 0; i < m; i++) {
        cnt1[grid[i][i]]++;
        cnt1[grid[i][n - 1 - i]]++;
        for (int j = 0; j < n; j++) {
            if (j != i && j != n - 1 - i) {
                cnt2[grid[i][j]]++;
            }
        }
    }
    for (int i = m; i < n; i++) {
        cnt1[grid[i][m]]++;
        for (int j = 0; j < n; j++) {
            if (j != m) {
                cnt2[grid[i][j]]++;
            }
        }
    }
    int maxNotChange = 0;
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            if (i != j) {
                maxNotChange = Math.max(maxNotChange, cnt1[i] + cnt2[j]);
            }
        }
    }
    return n * n - maxNotChange;
}

reference_code:
def minimumOperationsToWriteY( grid: List[List[int]]) -> int:
    cnt1 = [0] * 3
    cnt2 = [0] * 3
    n = len(grid)
    m = n // 2
    for i, row in enumerate(grid[:m]):
        cnt1[row[i]] += 1
        cnt1[row[-1 - i]] += 1
        for j, x in enumerate(row):
            if j != i and j != n - 1 - i:
                cnt2[x] += 1
    for row in grid[m:]:
        cnt1[row[m]] += 1
        for j, x in enumerate(row):
            if j != m:
                cnt2[x] += 1
    max_not_change = 0
    for i, c1 in enumerate(cnt1):
        for j, c2 in enumerate(cnt2):
            if i != j:
                max_not_change = max(max_not_change, c1 + c2)
    return n * n - max_not_change

