public static int minimumOperationsToMakeKPeriodic(String word, int k) {
    int n = word.length();
    int mx = 0;
    HashMap<String, Integer> cnt = new HashMap<>();
    for (int i = k; i <= n; i += k) {
        String sub = word.substring(i - k, i);
        int c = cnt.merge(sub, 1, Integer::sum); 
        mx = Math.max(mx, c);
    }
    return n / k - mx;
}

