public static int minimumLevels(int[] possible) {

    int n = possible.length;
    int s = 0;
    for (int x : possible) {
        s += x;
    }
    s = s * 2 - n;
    int pre = 0;
    for (int i = 0; i < n - 1; i++) {
        pre += possible[i] == 1 ? 2 : -2;
        if (pre > s) {
            return i + 1;
        }
    }
    return -1;
}

reference_code:
def minimumLevels( possible: List[int]) -> int:

    s = sum(possible) * 2 - len(possible)
    pre = 0
    for i, x in enumerate(possible[:-1]):
        pre += 2 if x else -2
        if pre > s:
            return i + 1
    return -1

