public static int maximumBeauty(int[] nums, int k) {
    int res = 0, n = nums.length;
    Arrays.sort(nums);
    for (int i = 0, j = 0; i < n; i++) {
        while (nums[i] - 2 * k > nums[j]) {
            j++;
        }
        res = Math.max(res, i - j + 1);
    }
    return res;
}

