public static int findMinimumTime(int[][] tasks) {
    int n = tasks.length;
    Arrays.sort(tasks, (a, b) -> a[1] - b[1]);
    int[] run = new int[tasks[n - 1][1] + 1];
    int res = 0;
    for (int i = 0; i < n; i++) {
        int start = tasks[i][0], end = tasks[i][1], duration = tasks[i][2];
        for (int j = start; j <= end; j++) {
            duration -= run[j];
        }
        res += Math.max(duration, 0);
        for (int j = end; j >= 0 && duration > 0; j--) {
            if (run[j] == 0) {
                duration--;
                run[j] = 1;
            }
        }
    }
    return res;
}

reference_code:
def findMinimumTime( tasks: List[List[int]]) -> int:
    tasks.sort(key = lambda task: task[1])
    run, res = [False] * (tasks[-1][1] + 1), 0
    for start, end, duration in tasks:
        duration -= sum(run[start : end+1])
        res += max(duration, 0)
        for j in range(end, -1, -1):
            if duration <= 0:
                break
            if not run[j]:
                run[j], duration = True, duration - 1
    return res

