public static long totalCost(int[] costs, int k, int candidates) {
    int n = costs.length;
    PriorityQueue<int[]> pq = new PriorityQueue<int[]>((a, b) -> a[0] != b[0] ? a[0] - b[0] : a[1] - b[1]);
    int left = candidates - 1, right = n - candidates;
    if (left + 1 < right) {
        for (int i = 0; i <= left; ++i) {
            pq.offer(new int[]{costs[i], i});
        }
        for (int i = right; i < n; ++i) {
            pq.offer(new int[]{costs[i], i});
        }
    } else {
        for (int i = 0; i < n; ++i) {
            pq.offer(new int[]{costs[i], i});
        }
    }
    long ans = 0;
    for (int i = 0; i < k; ++i) {
        int[] arr = pq.poll();
        int cost = arr[0], id = arr[1];
        ans += cost;
        if (left + 1 < right) {
            if (id <= left) {
                ++left;
                pq.offer(new int[]{costs[left], left});
            } else {
                --right;
                pq.offer(new int[]{costs[right], right});
            }
        }
    }
    return ans;
}

reference_code:
def totalCost( costs: List[int], k: int, candidates: int) -> int:
    n = len(costs)
    q = list()
    left, right = candidates - 1, n - candidates
    if left + 1 < right:
        for i in range(left + 1):
            heappush(q, (costs[i], i))
        for i in range(right, n):
            heappush(q, (costs[i], i))
    else:
        for i in range(n):
            heappush(q, (costs[i], i))
    ans = 0
    for _ in range(k):
        cost, idx = heappop(q)
        ans += cost
        if left + 1 < right:
            if idx <= left:
                left += 1
                heappush(q, (costs[left], left))
            else:
                right -= 1
                heappush(q, (costs[right], right))
    return ans

