public static int findChampion(int n, int[][] edges) {
    int[] degree = new int[n];
    for (int[] e : edges) {
        degree[e[1]]++;
    }
    int champion = -1;
    for (int i = 0; i < n; i++) {
        if (degree[i] == 0) {
            if (champion == -1) {
                champion = i;
            } else {
                return -1;
            }
        }
    }
    return champion;
}

