public static int minIncrements(int n, int[] cost) {
    int ans = 0;
    for (int i = n - 2; i > 0; i -= 2) {
        ans += Math.abs(cost[i] - cost[i + 1]);

        cost[i / 2] += Math.max(cost[i], cost[i + 1]);
    }
    return ans;
}

