public static int minElements(int n, int m, int[] arr1, int[] arr2) {
    long sum = 0;

    for (int num : arr1) {
        sum += num;
    }
    Arrays.sort(arr2); 
    long currentSum = 0;
    int count = 0;

    for (int i = m - 1; i >= 0; i--) {
        currentSum += arr2[i];
        count++;

        if (currentSum >= sum) {
            break;
        }
    }

    return currentSum >= sum ? count : -1;
}

