public static int maxFrequencyElements(int[] nums) {
    int ans = 0, maxCnt = 0;
    Map<Integer, Integer> cnt = new HashMap<>();
    for (int x : nums) {
        int c = cnt.merge(x, 1, Integer::sum);
        if (c > maxCnt) {
