public static int minimumArrayLength(int[] nums) {
    int m = Integer.MAX_VALUE;
    for (int x : nums) {
        m = Math.min(m, x);
    }
    for (int x : nums) {
        if (x % m > 0) {
            return 1;
        }
    }
    int cnt = 0;
    for (int x : nums) {
        if (x == m) {
            cnt++;
        }
    }
    return (cnt + 1) / 2;
}

