public static long countAlternatingSubarrays(int[] nums) {
    long res = 0, cur = 0;
    int pre = -1;
    for (int a : nums) {
        cur = (pre != a) ? cur + 1 : 1;
        pre = a;
        res += cur;
    }
    return res;
}

