public static int paintWalls(int[] cost, int[] time) {
    int n = cost.length;
    int[] f = new int[n * 2 + 1];
    Arrays.fill(f, Integer.MAX_VALUE / 2);
    f[n] = 0;
    for (int i = 0; i < n; ++i) {
        int[] g = new int[n * 2 + 1];
        Arrays.fill(g, Integer.MAX_VALUE / 2);
        for (int j = 0; j <= n * 2; ++j) {

            g[Math.min(j + time[i], n * 2)] = Math.min(g[Math.min(j + time[i], n * 2)], f[j] + cost[i]);

            if (j > 0) {
                g[j - 1] = Math.min(g[j - 1], f[j]);
            }
        }
        f = g;
    }
    int ans = f[n];
    for (int i = n + 1; i <= n * 2; i++) {
        ans = Math.min(ans, f[i]);
    }
    return ans;
}

reference_code:
def paintWalls( cost: List[int], time: List[int]) -> int:
    n = len(cost)
    f = [inf] * (n * 2 + 1)
    f[n] = 0
    for (cost_i, time_i) in zip(cost, time):
        g = [inf] * (n * 2 + 1)
        for j in range(n * 2 + 1):

            g[min(j + time_i, n * 2)] = min(g[min(j + time_i, n * 2)], f[j] + cost_i)

            if j > 0:
                g[j - 1] = min(g[j - 1], f[j])
        f = g
    return min(f[n:])

