public static long pickGifts(int[] gifts, int k) {
        PriorityQueue<Integer> pq = new PriorityQueue<Integer>((a, b) -> b - a);
        for (int gift : gifts) {
            pq.offer(gift);
        }
        while (k > 0) {
            k--;
            int x = pq.poll();
            pq.offer((int) Math.sqrt(x));
        }
        long res = 0;
        while (!pq.isEmpty()) {
            res += pq.poll();
        }
        return res;
    }

reference_code:
def pickGifts( gifts: List[int], k: int) -> int:
        q = [-gift for gift in gifts]
        heapify(q)
        while k:
            x = heappop(q)
            heappush(q, -int(sqrt(-x)))
            k -= 1
        return -sum(q)

