def distMoney( money: int, children: int) -> int:
        if money < children:
            return -1
        money -= children
        cnt = min(money // 7, children)
        money -= cnt * 7
        children -= cnt
        if (children == 0 and money > 0) or (children == 1 and money == 3):
            cnt -= 1
        return cnt

