public static int giveGem(int[] gem, int[][] operations) {
        for (int[] operation : operations) {
            int x = operation[0], y = operation[1];
            int number = gem[x] / 2;
            gem[x] -= number;
            gem[y] += number;
        }
        int mn = gem[0], mx = gem[0];
        for (int number : gem) {
            mn = Math.min(number, mn);
            mx = Math.max(number, mx);
        }
        return mx - mn;
    }

reference_code:
def giveGem( gem: List[int], operations: List[List[int]]) -> int:
        for x, y in operations:
            number = gem[x] // 2
            gem[x] -= number
            gem[y] += number
        mn, mx = gem[0], gem[0]
        for number in gem:
            mn = min(number, mn)
            mx = max(number, mx)
        return mx - mn

