public static int[] shortestDistanceAfterQueries2(int n, int[][] queries) {
        int[] nxt = new int[n - 1];
        for (int i = 0; i < n - 1; i++) {
            nxt[i] = i + 1;
        }
        int[] ans = new int[queries.length];
        int cnt = n - 1;
        for (int qi = 0; qi < queries.length; qi++) {
            int l = queries[qi][0];
            int r = queries[qi][1];
            if (nxt[l] > 0 && nxt[l] < r) {
                for (int i = nxt[l]; i < r;) {
                    cnt--;
                    int tmp = nxt[i];
                    nxt[i] = 0;
                    i = tmp;
                }
                nxt[l] = r;
            }
            ans[qi] = cnt;
        }
        return ans;
    }

reference_code:
def shortestDistanceAfterQueries2(n: int, queries: List[List[int]]) -> List[int]:
    ans = []
    nxt = list(range(1, n))
    cnt = n - 1
    for l, r in queries:
        if 0 < nxt[l] < r:
            i = nxt[l]
            while i < r:
                cnt -= 1
                nxt[i], i = 0, nxt[i]
            nxt[l] = r
        ans.append(cnt)
    return ans

