public static int winningPlayerCount(int n, int[][] pick) {
        int[][] cnts = new int[n][11];
        for (int[] p : pick) {
            cnts[p[0]][p[1]]++;
        }
        int ans = 0;
        for (int i = 0; i < n; i++) {
