public static int minFlips(int[][] grid) {
    int m = grid.length;
    int n = grid[0].length;
    int diffRow = 0;
    for (int[] row : grid) {
        for (int j = 0; j < n / 2; j++) {
            if (row[j] != row[n - 1 - j]) {
                diffRow++;
            }
        }
    }
    int diffCol = 0;
    for (int j = 0; j < n; j++) {
        for (int i = 0; i < m / 2; i++) {
            if (grid[i][j] != grid[m - 1 - i][j]) {
                diffCol++;
            }
        }
    }
    return Math.min(diffRow, diffCol);
}

reference_code:
def minFlips( grid: List[List[int]]) -> int:
        diff_row = 0
        for row in grid:
            for j in range(len(row) // 2):
                if row[j] != row[-1 - j]:
                    diff_row += 1
        diff_col = 0
        for col in zip(*grid):
            for i in range(len(grid) // 2):
                if col[i] != col[-1 - i]:
                    diff_col += 1
        return min(diff_row, diff_col)

