                flag = True
                continue
            if flag:
                if (x & (1 << i)) == 0 and prev == -1:
                    prev = i
                    x |= (1 << i)
                    cnt += 1
                if (x & (1 << i)) == 0 and prev - i > 1:
                    x |= (1 << i)
                    cnt += 1
        return x

