public static long getCount(int n, int[] arr, int a, int b) {

    int ans = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            boolean flag = false;
            for (int k = i; k <= j; k++) {
                for (int l = k + 1; l <= j; l++) {
                    if (arr[k] + arr[l] < a || arr[k] + arr[l] > b) {
                        flag = true;
                    }
                }
            }
            if (!flag) ans++;
        }
    }
    return ans;
}

