public static int minDifference(int n, int[] arr, int x) {
        int ans = n + 1;
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                if ((arr[i] ^ arr[j]) <= x) {
                    ans = Math.min(ans, j - i);
                }
            }
        }
        return (ans == n + 1) ? -1 : ans;
    }

