public static boolean matrixConundrum(int n, int m, List<String> mat) {
    String play = "play";
    int fnd = 0;
    for (int i = 0; i < m; ++i) {
        boolean check = false;
        for (int j = 0; j < n; ++j) {
            if (mat.get(j).charAt(i) == play.charAt(fnd)) {
                check = true;
            }
        }
        if (check) {
            ++fnd;
            if (fnd == 4) {
                break;
            }
        }
    }
    return fnd == 4;
}

