public static double minimumAverage(int[] nums) {
    Arrays.sort(nums);
    int ans = Integer.MAX_VALUE;
    int n = nums.length;
    for (int i = 0; i < n / 2; i++) {
        ans = Math.min(ans, nums[i] + nums[n - 1 - i]);
    }
    return ans / 2.0;
}

