public static int minimumTime(List<Integer> nums1, List<Integer> nums2, int x) {
    int n = nums1.size(), s1 = 0, s2 = 0;
    int[][] dp = new int[n + 1][n + 1];
    List<List<Integer>> nums = new ArrayList<>();
    for (int i = 0; i < n; i++) {
        int a = nums1.get(i), b = nums2.get(i);
        nums.add(Arrays.asList(b, a));
        s1 += a;
        s2 += b;
    }
    Collections.sort(nums, (o1, o2) -> Integer.compare(o1.get(0), o2.get(0)));
    for (int j = 1; j <= n; ++j) {
        int b = nums.get(j - 1).get(0), a = nums.get(j - 1).get(1);
        for (int i = j; i > 0; --i) {
            dp[j][i] = Math.max(dp[j - 1][i], dp[j - 1][i - 1] + i * b + a);
        }
    }
    for (int i = 0; i <= n; i++) {
        if (s2 * i + s1 - dp[n][i] <= x) {
            return i;
        }
    }
    return -1;
}

reference_code:
def minimumTime( nums1: List[int], nums2: List[int], x: int) -> int:
    n = len(nums1)
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    for j, (b, a) in enumerate(sorted(zip(nums2, nums1)), 1):
        for i in range(j, 0, -1):
            dp[j][i] = max(dp[j - 1][i], dp[j - 1][i - 1] + i * b + a)
    sa, sb = sum(nums1), sum(nums2)
    for i in range(0, n + 1):
        if sb * i + sa - dp[n][i] <= x:
            return i
    return -1

