public static int maximumLength(int[] nums, int k) {
    int ans = 0;
    int[][] f = new int[k][k];
    for (int x : nums) {
        x %= k;
        for (int y = 0; y < k; y++) {
            f[y][x] = f[x][y] + 1;
            ans = Math.max(ans, f[y][x]);
        }
    }
    return ans;
}

