public static ArrayList<Integer> BeautifulBits(int n, int[] arr, int q,
                                               int[][] queries) {
    long[][] pref = new long[n + 1][32];
    for (int i = 1; i <= n; i++) {
        for (int j = 0; j < 32; j++) {
            pref[i][j] = pref[i - 1][j] + ((arr[i - 1] >> j) & 1);
        }
    }
    ArrayList<Integer> ans = new ArrayList<>(Collections.nCopies(q, 0));
    for (int i = 0; i < q; i++) {
        for (int j = 0; j < 32; j++) {
            if (pref[queries[i][1]][j] - pref[queries[i][0] - 1][j] != 0) {
                ans.set(i, ans.get(i) + (1 << j));
            }
        }
    }
    return ans;
}

reference_code:
def BeautifulBits( n : int, arr : List[int], q : int, queries : List[List[int]]) -> List[int]:
    pref = [[0] * 32 for _ in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(32):
            pref[i][j] = pref[i - 1][j] + ((arr[i - 1] >> j) & 1)
    ans = [0] * q
    for i in range(q):
        for j in range(32):
            if pref[queries[i][1]][j] - pref[queries[i][0] - 1][j] != 0:
                ans[i] += 1 << j
    return ans

