public static boolean canSortArray(int[] nums) {
    int lastCnt = 0;
    int lastGroupMax = 0;
    int curGroupMax = 0;
    for (int num : nums) {
        int curCnt = Integer.bitCount(num);
        if (curCnt == lastCnt) {
            curGroupMax = Math.max(curGroupMax, num);
        } else {
            lastCnt = curCnt;
            lastGroupMax = curGroupMax;
            curGroupMax = num;
        }
        if (num < lastGroupMax) {
            return false;
        }
    }
    return true;
}

