public static int minPathCost(int[][] grid, int[][] moveCost) {
        int m = grid.length, n = grid[0].length;
        int[][] dp = new int[2][n];
        dp[0] = grid[0].clone();
        int cur = 0;
        for (int i = 1; i < m; i++) {
            int next = 1 - cur;
            for (int j = 0; j < n; j++) {
                dp[next][j] = Integer.MAX_VALUE;
                for (int k = 0; k < n; k++) {
                    dp[next][j] = Math.min(dp[next][j], dp[cur][k] + moveCost[grid[i - 1][k]][j] + grid[i][j]);
                }
            }
            cur = next;
        }
        return Arrays.stream(dp[cur]).min().getAsInt();
    }

reference_code:
def minPathCost( grid: List[List[int]], moveCost: List[List[int]]) -> int:
       m, n = len(grid), len(grid[0])
       dp = grid[0]
       for i in range(1, len(grid)):
           dp = [grid[i][j] + min(dp[k] + moveCost[grid[i - 1][k]][j] for k in range(n)) for j in range(n)]
       return min(dp)

