public static int minOPs(int n, int[] A) {
    Map<Integer, Integer> m = new HashMap<>();
    for (int it : A) {
        m.put(it, m.getOrDefault(it, 0) + 1);
    }
    int[] v = new int[m.size()];
    int index = 0;
    for (int value : m.values()) {
        v[index++] = value;
    }
    Arrays.sort(v);
    int sum = 0;
    for (int i = v.length - 1; i >= 0; i--) {
        sum += v[i];
        if (sum > (n / 2)) {
            return v.length - 1 - i;
        }
    }
    return 0; 
}

