public static ArrayList<Integer> substringsAndPermutations(int n, int m, String s,
                                                    String[] arr) {
    Map<Character, List<Integer>> mp = new HashMap<>();
    for (int i = 0; i < n; i++) {
        char ch = s.charAt(i);
        mp.computeIfAbsent(ch, k -> new ArrayList<>()).add(i);
    }
    ArrayList<Integer> ans = new ArrayList<>();
    for (int q = 0; q < m; q++) {
        String query = arr[q];
        int ma = 0;
        Map<Character, Integer> ct = new HashMap<>();
        for (char c : query.toCharArray()) {
            ct.put(c, ct.getOrDefault(c, 0) + 1);
        }
        for (char c : query.toCharArray()) {
            int ele = ct.get(c);
            if (ele > mp.getOrDefault(c, Collections.emptyList()).size()) {
                ma = -1;
                break;
            } else {
                ma = Math.max(ma, mp.get(c).get(ele - 1) + 1);
            }
        }
        ans.add(ma);
    }
    return ans;
}

