def substringsAndPermutations( n: int, m: int, s: str,
                              arr: List[str]) -> List[int]:
    vec = [[] for _ in range(10)]
    for i in range(n):
        vec[int(s[i])].append(i + 1)
    fans = []
    for i in range(m):
        brr = [0] * 10
        for j in range(len(arr[i])):
            brr[int(arr[i][j])] += 1
        ans = -1
        f = 0
        for j in range(10):
            if brr[j] != 0:
                if len(vec[j]) < brr[j]:
                    f = 1
                else:
                    ans = max(ans, vec[j][brr[j] - 1])
        if f == 1:
            ans = -1
        fans.append(ans)
    return fans

