public static int sumOfEncryptedInt(int[] nums) {
    int ans = 0;
    for (int x : nums) {
        int mx = 0;
        int base = 0;
        for (; x > 0; x /= 10) {
            mx = Math.max(mx, x % 10);
            base = base * 10 + 1;
        }
        ans += mx * base;
    }
    return ans;
}

