public static int bobHappiness(int n, int k, int q, int[][] students,
                               int[][] queries) {
    TreeSet<Integer> set1 = new TreeSet<>();
    TreeSet<Integer> set2 = new TreeSet<>();
    for (int[] a : students) {
        set1.add(a[0]);
        set2.add(a[1]);
    }
    Map<Integer, Integer> map1 = new HashMap<>();
    Map<Integer, Integer> map2 = new HashMap<>();
    int idx1 = 1, idx2 = 1;
    while (!set1.isEmpty()) {
        map1.put(set1.pollFirst(), idx1++);
        map2.put(set2.pollFirst(), idx2++);
    }
    int[][] pre = new int[n][n];
    for (int i = 0; i < n; i++) {
        pre[map1.get(students[i][0]) - 1][map2.get(students[i][1]) - 1]++;
    }
    int[][] Arr = new int[n + 1][n + 1];
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (pre[i - 1][j - 1] == 0) {
                Arr[i][j] = Arr[i - 1][j] + Arr[i][j - 1] - Arr[i - 1][j - 1];
            } else {
                Arr[i][j] = Arr[i - 1][j] + Arr[i][j - 1] + 1 - Arr[i - 1][j - 1];
            }
        }
    }
    int sum = 0;
    for (int i = 0; i < q; i++) {
        int X = queries[i][0], Y = queries[i][1];
        X--;
        Y--;
        int a = map1.get(students[Y][0]);
        int b = map2.get(students[Y][1]);
        int c = map1.get(students[X][0]), d = map2.get(students[X][1]);
        int temp = a;
        a = c;
        c = temp;
        int people = Arr[c][d] + Arr[a - 1][b - 1] - Arr[a - 1][d] - Arr[c][b - 1];
        people -= 2;
        if (people > k) {

        } else {
            sum++;
        }
    }
    return sum;
}

