public static long geekTasks(int n, int m, int q, int[][] tasks) {
    long total = 0;
    long minA = Long.MAX_VALUE, minB = Long.MAX_VALUE;

    for (int i = 0; i < q; i++) {
        int a = tasks[i][0] + 1;
        int b = tasks[i][1] + 1;
        minA = Math.min(minA, a);
        minB = Math.min(minB, b);
    }
    int[] col = new int[n]; 

    for (int[] task : tasks) {
        int x = task[1] + 1;
        col[task[0]] = Math.max(col[task[0]], x);
    }
    long maxColValue = 0;

    for (int i = n - 1; i >= 0; i--) {
        maxColValue = Math.max(maxColValue, col[i]);
        total += maxColValue;
    }
    long cellsWithMaxValue = minA * minB;

    return total - cellsWithMaxValue;
}

reference_code:
def geekTasks( n : int, m : int, q : int, tasks : List[List[int]]) -> int:
    minA=0
    minB=0
    for i in range(q):
        a,b=tasks[i][0],tasks[i][1]
        a+=1
        b+=1
        if i==0:
            minA=a
            minB=b
        else:
            if minA>a:
                minA=a
            if minB>b:
                minB=b
    total=0
    maxi=0
    col=[0]*(n)
    for i in range(q):
        col[tasks[i][0]]=max(col[tasks[i][0]],tasks[i][1]+1)
    for i in range(n-1,-1,-1):
        maxi=max(maxi,col[i])
        total+=maxi
    total-=minA*minB
    return total

